// ============================================================================
// OpCode: 가상 머신의 모든 연산 명령어
// ============================================================================

/// 바이트코드 명령어
#[repr(u8)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum OpCode {
    /// 상수 푸시: 상수 풀의 인덱스를 스택에 로드
    OpConstant = 0,

    /// 덧셈: 스택 상단 두 값을 더함
    OpAdd = 1,

    /// 뺄셈: 스택 상단 두 값을 뺌
    OpSub = 2,

    /// 곱셈: 스택 상단 두 값을 곱함
    OpMul = 3,

    /// 나눗셈: 스택 상단 두 값을 나눔
    OpDiv = 4,

    /// 불리언 참: true를 스택에 푸시
    OpTrue = 5,

    /// 불리언 거짓: false를 스택에 푸시
    OpFalse = 6,

    /// 비교 같음: ==
    OpEqual = 7,

    /// 비교 같지 않음: !=
    OpNotEqual = 8,

    /// 비교 미만: <
    OpLessThan = 9,

    /// 비교 이상: >=
    OpGreaterThanOrEqual = 10,

    /// 부정: ! (스택 상단값)
    OpBang = 11,

    /// 음수: - (스택 상단값)
    OpMinus = 12,

    /// 점프: 조건 없이 지정된 위치로 이동
    OpJump = 13,

    /// 조건부 점프: 스택 상단이 거짓이면 점프
    OpJumpNotTruthy = 14,

    /// Null: null 값을 스택에 푸시
    OpNull = 15,

    /// 팝: 스택 상단값 제거
    OpPop = 16,

    /// 반환: 함수에서 반환 (값 있음)
    OpReturnValue = 17,

    /// 반환: 함수에서 반환 (값 없음)
    OpReturn = 18,

    /// 변수 로드: 로컬 저장소에서 변수 로드
    OpGetLocal = 19,

    /// 변수 저장: 로컬 저장소에 변수 저장
    OpSetLocal = 20,

    /// 배열 구성: N개의 요소로 배열 생성
    OpArray = 21,

    /// 해시맵 구성: K,V 쌍으로 해시맵 생성
    OpHash = 22,

    /// 인덱싱: 배열/해시맵에서 인덱싱
    OpIndex = 23,

    /// 함수 호출: N개 인자로 함수 호출
    OpCall = 24,

    /// 프로그램 종료
    OpEnd = 255,
}

impl OpCode {
    /// OpCode를 바이트로 변환
    pub fn as_byte(self) -> u8 {
        self as u8
    }

    /// 바이트를 OpCode로 변환
    pub fn from_byte(byte: u8) -> Option<Self> {
        match byte {
            0 => Some(OpCode::OpConstant),
            1 => Some(OpCode::OpAdd),
            2 => Some(OpCode::OpSub),
            3 => Some(OpCode::OpMul),
            4 => Some(OpCode::OpDiv),
            5 => Some(OpCode::OpTrue),
            6 => Some(OpCode::OpFalse),
            7 => Some(OpCode::OpEqual),
            8 => Some(OpCode::OpNotEqual),
            9 => Some(OpCode::OpLessThan),
            10 => Some(OpCode::OpGreaterThanOrEqual),
            11 => Some(OpCode::OpBang),
            12 => Some(OpCode::OpMinus),
            13 => Some(OpCode::OpJump),
            14 => Some(OpCode::OpJumpNotTruthy),
            15 => Some(OpCode::OpNull),
            16 => Some(OpCode::OpPop),
            17 => Some(OpCode::OpReturnValue),
            18 => Some(OpCode::OpReturn),
            19 => Some(OpCode::OpGetLocal),
            20 => Some(OpCode::OpSetLocal),
            21 => Some(OpCode::OpArray),
            22 => Some(OpCode::OpHash),
            23 => Some(OpCode::OpIndex),
            24 => Some(OpCode::OpCall),
            255 => Some(OpCode::OpEnd),
            _ => None,
        }
    }

    /// OpCode 이름
    pub fn name(&self) -> &'static str {
        match self {
            OpCode::OpConstant => "CONSTANT",
            OpCode::OpAdd => "ADD",
            OpCode::OpSub => "SUB",
            OpCode::OpMul => "MUL",
            OpCode::OpDiv => "DIV",
            OpCode::OpTrue => "TRUE",
            OpCode::OpFalse => "FALSE",
            OpCode::OpEqual => "EQUAL",
            OpCode::OpNotEqual => "NOT_EQUAL",
            OpCode::OpLessThan => "LESS_THAN",
            OpCode::OpGreaterThanOrEqual => "GREATER_EQUAL",
            OpCode::OpBang => "BANG",
            OpCode::OpMinus => "MINUS",
            OpCode::OpJump => "JUMP",
            OpCode::OpJumpNotTruthy => "JUMP_NOT_TRUTHY",
            OpCode::OpNull => "NULL",
            OpCode::OpPop => "POP",
            OpCode::OpReturnValue => "RETURN_VALUE",
            OpCode::OpReturn => "RETURN",
            OpCode::OpGetLocal => "GET_LOCAL",
            OpCode::OpSetLocal => "SET_LOCAL",
            OpCode::OpArray => "ARRAY",
            OpCode::OpHash => "HASH",
            OpCode::OpIndex => "INDEX",
            OpCode::OpCall => "CALL",
            OpCode::OpEnd => "END",
        }
    }

    /// 피연산자 수 반환
    pub fn operand_width(&self) -> usize {
        match self {
            // 인덱스(2바이트): u16
            OpCode::OpConstant => 2,
            OpCode::OpJump => 2,
            OpCode::OpJumpNotTruthy => 2,
            OpCode::OpGetLocal => 1,
            OpCode::OpSetLocal => 1,
            OpCode::OpArray => 2,
            OpCode::OpHash => 2,
            OpCode::OpCall => 1,
            // 피연산자 없음
            _ => 0,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_opcode_round_trip() {
        let opcodes = vec![
            OpCode::OpConstant,
            OpCode::OpAdd,
            OpCode::OpTrue,
            OpCode::OpFalse,
        ];

        for op in opcodes {
            let byte = op.as_byte();
            let recovered = OpCode::from_byte(byte).unwrap();
            assert_eq!(op, recovered);
        }
    }

    #[test]
    fn test_operand_widths() {
        assert_eq!(OpCode::OpConstant.operand_width(), 2);
        assert_eq!(OpCode::OpAdd.operand_width(), 0);
        assert_eq!(OpCode::OpTrue.operand_width(), 0);
        assert_eq!(OpCode::OpJump.operand_width(), 2);
    }
}

