// ============================================================================
// Bytecode: 컴파일된 명령어와 상수
// ============================================================================


/// 컴파일된 바이트코드
#[derive(Debug, Clone)]
pub struct Bytecode {
    /// 명령어 바이트 스트림
    pub instructions: Vec<u8>,

    /// 상수 풀 (정수)
    pub constants: Vec<i64>,
}

impl Bytecode {
    /// 새로운 바이트코드 생성
    pub fn new() -> Self {
        Bytecode {
            instructions: Vec::new(),
            constants: Vec::new(),
        }
    }

    /// 명령어 길이
    pub fn len(&self) -> usize {
        self.instructions.len()
    }

    /// 상수 추가
    pub fn add_constant(&mut self, value: i64) -> usize {
        self.constants.push(value);
        self.constants.len() - 1
    }

    /// 명령어 추가
    pub fn add_instruction(&mut self, instruction: u8) {
        self.instructions.push(instruction);
    }

    /// 명령어 범위 조회
    pub fn get_instructions(&self, start: usize, end: usize) -> Option<&[u8]> {
        if start < end && end <= self.instructions.len() {
            Some(&self.instructions[start..end])
        } else {
            None
        }
    }

    /// 지정된 위치의 상수 조회
    pub fn get_constant(&self, index: usize) -> Option<i64> {
        self.constants.get(index).copied()
    }
}

impl Default for Bytecode {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::opcode::OpCode;

    #[test]
    fn test_add_constant() {
        let mut bytecode = Bytecode::new();
        let idx1 = bytecode.add_constant(100);
        let idx2 = bytecode.add_constant(200);

        assert_eq!(idx1, 0);
        assert_eq!(idx2, 1);
        assert_eq!(bytecode.get_constant(0), Some(100));
        assert_eq!(bytecode.get_constant(1), Some(200));
    }

    #[test]
    fn test_add_instruction() {
        let mut bytecode = Bytecode::new();
        bytecode.add_instruction(OpCode::OpConstant.as_byte());
        bytecode.add_instruction(0);  // 상수 인덱스 high byte
        bytecode.add_instruction(0);  // 상수 인덱스 low byte

        assert_eq!(bytecode.len(), 3);
    }
}

// ============================================================================
// AST: Abstract Syntax Tree
// ============================================================================

/// 표현식
#[derive(Debug, Clone, PartialEq)]
pub enum Expression {
    /// 정수 리터럴
    Integer(i64),

    /// 불리언 리터럴
    Boolean(bool),

    /// 식별자
    Identifier(String),

    /// 전위 연산: !x, -5
    Prefix(String, Box<Expression>),

    /// 중위 연산: x + y
    Infix(String, Box<Expression>, Box<Expression>),

    /// if 표현식
    If {
        condition: Box<Expression>,
        consequence: Vec<Statement>,
        alternative: Option<Vec<Statement>>,
    },

    /// 함수 호출
    Call {
        function: Box<Expression>,
        arguments: Vec<Expression>,
    },

    /// 배열 리터럴
    Array(Vec<Expression>),

    /// 인덱싱
    Index(Box<Expression>, Box<Expression>),

    /// null
    Null,
}

/// 문장
#[derive(Debug, Clone, PartialEq)]
pub enum Statement {
    /// 변수 선언: let x = 10;
    Let {
        name: String,
        value: Expression,
    },

    /// 표현식 문장
    Expression(Expression),

    /// 반환: return 42;
    Return(Expression),

    /// 블록
    Block(Vec<Statement>),
}

/// 프로그램
#[derive(Debug, Clone)]
pub struct Program {
    pub statements: Vec<Statement>,
}

impl Program {
    pub fn new(statements: Vec<Statement>) -> Self {
        Program { statements }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_expression_integer() {
        let expr = Expression::Integer(42);
        match expr {
            Expression::Integer(n) => assert_eq!(n, 42),
            _ => panic!("Expected Integer"),
        }
    }

    #[test]
    fn test_expression_infix() {
        let expr = Expression::Infix(
            "+".to_string(),
            Box::new(Expression::Integer(5)),
            Box::new(Expression::Integer(3)),
        );

        match expr {
            Expression::Infix(op, _, _) => assert_eq!(op, "+"),
            _ => panic!("Expected Infix"),
        }
    }
}

