// ============================================================================
// VM: Virtual Machine - 바이트코드 실행 엔진
// ============================================================================

use crate::bytecode::Bytecode;
use crate::opcode::OpCode;
use crate::value::Value;
use std::collections::HashMap;

/// 가상 머신
pub struct VM {
    bytecode: Bytecode,
    stack: Vec<Value>,
    ip: usize, // Instruction Pointer
}

impl VM {
    /// 새로운 VM 생성
    pub fn new(bytecode: Bytecode) -> Self {
        VM {
            bytecode,
            stack: Vec::with_capacity(256),
            ip: 0,
        }
    }

    /// 바이트코드 실행
    pub fn run(&mut self) -> Result<Value, String> {
        while self.ip < self.bytecode.instructions.len() {
            let op_byte = self.bytecode.instructions[self.ip];
            self.ip += 1;

            let op = OpCode::from_byte(op_byte).ok_or(format!("Unknown opcode: {}", op_byte))?;

            match op {
                OpCode::OpConstant => {
                    let idx = self.read_u16() as usize;
                    let val = self
                        .bytecode
                        .get_constant(idx)
                        .ok_or(format!("Constant index out of bounds: {}", idx))?;
                    self.stack.push(Value::Int(val));
                }

                OpCode::OpAdd => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            self.stack.push(Value::Int(l + r));
                        }
                        _ => return Err("Cannot add non-integers".to_string()),
                    }
                }

                OpCode::OpSub => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            self.stack.push(Value::Int(l - r));
                        }
                        _ => return Err("Cannot subtract non-integers".to_string()),
                    }
                }

                OpCode::OpMul => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            self.stack.push(Value::Int(l * r));
                        }
                        _ => return Err("Cannot multiply non-integers".to_string()),
                    }
                }

                OpCode::OpDiv => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            if r == 0 {
                                return Err("Division by zero".to_string());
                            }
                            self.stack.push(Value::Int(l / r));
                        }
                        _ => return Err("Cannot divide non-integers".to_string()),
                    }
                }

                OpCode::OpTrue => {
                    self.stack.push(Value::Bool(true));
                }

                OpCode::OpFalse => {
                    self.stack.push(Value::Bool(false));
                }

                OpCode::OpEqual => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    self.stack.push(Value::Bool(left == right));
                }

                OpCode::OpNotEqual => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    self.stack.push(Value::Bool(left != right));
                }

                OpCode::OpLessThan => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            self.stack.push(Value::Bool(l < r));
                        }
                        _ => return Err("Cannot compare non-integers".to_string()),
                    }
                }

                OpCode::OpGreaterThanOrEqual => {
                    let right = self.stack_pop()?;
                    let left = self.stack_pop()?;
                    match (left, right) {
                        (Value::Int(l), Value::Int(r)) => {
                            self.stack.push(Value::Bool(l >= r));
                        }
                        _ => return Err("Cannot compare non-integers".to_string()),
                    }
                }

                OpCode::OpBang => {
                    let val = self.stack_pop()?;
                    self.stack.push(Value::Bool(!val.is_truthy()));
                }

                OpCode::OpMinus => {
                    let val = self.stack_pop()?;
                    match val {
                        Value::Int(n) => self.stack.push(Value::Int(-n)),
                        _ => return Err("Cannot negate non-integer".to_string()),
                    }
                }

                OpCode::OpJump => {
                    let target = self.read_u16() as usize;
                    self.ip = target;
                }

                OpCode::OpJumpNotTruthy => {
                    let target = self.read_u16() as usize;
                    let cond = self.stack_pop()?;
                    if !cond.is_truthy() {
                        self.ip = target;
                    }
                }

                OpCode::OpNull => {
                    self.stack.push(Value::Null);
                }

                OpCode::OpPop => {
                    let _ = self.stack_pop()?;
                }

                OpCode::OpArray => {
                    let count = self.read_u16() as usize;
                    let mut arr = Vec::with_capacity(count);
                    for _ in 0..count {
                        arr.push(self.stack_pop()?);
                    }
                    arr.reverse();
                    self.stack.push(Value::Array(arr));
                }

                OpCode::OpHash => {
                    let count = self.read_u16() as usize;
                    let mut map = HashMap::new();
                    for _ in 0..count {
                        let val = self.stack_pop()?;
                        let key = match self.stack_pop()? {
                            Value::Int(n) => n.to_string(),
                            _ => return Err("Hash keys must be integers".to_string()),
                        };
                        map.insert(key, val);
                    }
                    self.stack.push(Value::HashMap(map));
                }

                OpCode::OpIndex => {
                    let idx = self.stack_pop()?;
                    let arr = self.stack_pop()?;

                    match (arr, idx) {
                        (Value::Array(arr), Value::Int(i)) => {
                            let idx = if i < 0 {
                                (arr.len() as i64 + i) as usize
                            } else {
                                i as usize
                            };

                            if idx < arr.len() {
                                self.stack.push(arr[idx].clone());
                            } else {
                                self.stack.push(Value::Null);
                            }
                        }
                        (Value::HashMap(map), key_val) => {
                            let key = match key_val {
                                Value::Int(n) => n.to_string(),
                                _ => return Err("Hash keys must be integers".to_string()),
                            };
                            match map.get(&key) {
                                Some(val) => self.stack.push(val.clone()),
                                None => self.stack.push(Value::Null),
                            }
                        }
                        _ => return Err("Invalid indexing operation".to_string()),
                    }
                }

                OpCode::OpReturnValue | OpCode::OpReturn => {
                    if let OpCode::OpReturnValue = op {
                        return self.stack_pop();
                    } else {
                        return Ok(Value::Null);
                    }
                }

                OpCode::OpEnd => {
                    break;
                }

                _ => return Err(format!("Unimplemented opcode: {:?}", op)),
            }
        }

        // 스택에 값이 남아있으면 반환
        if !self.stack.is_empty() {
            self.stack_pop()
        } else {
            Ok(Value::Null)
        }
    }

    /// 스택에서 2바이트 읽기 (Big-Endian)
    fn read_u16(&mut self) -> u16 {
        let high = self.bytecode.instructions[self.ip] as u16;
        let low = self.bytecode.instructions[self.ip + 1] as u16;
        self.ip += 2;
        (high << 8) | low
    }

    /// 스택에서 값 팝
    fn stack_pop(&mut self) -> Result<Value, String> {
        self.stack.pop().ok_or_else(|| "Stack underflow".to_string())
    }

    /// 스택의 최상단 값 조회 (팝하지 않음)
    pub fn stack_peek(&self) -> Option<&Value> {
        self.stack.last()
    }

    /// 스택 상태 확인
    pub fn stack(&self) -> &[Value] {
        &self.stack
    }
}

