// ============================================================================
// Disassembler: 바이트코드를 읽을 수 있는 형태로 변환
// ============================================================================

use crate::bytecode::Bytecode;
use crate::opcode::OpCode;

/// 바이트코드를 인간이 읽을 수 있는 형태로 변환
pub struct Disassembler;

impl Disassembler {
    /// 전체 바이트코드를 문자열로 변환
    pub fn disassemble(bytecode: &Bytecode) -> String {
        let mut output = String::new();
        output.push_str("=== Bytecode Disassembly ===\n");
        output.push_str("Instructions:\n");

        let mut ip = 0;
        while ip < bytecode.instructions.len() {
            let instruction = bytecode.instructions[ip];
            if let Some(opcode) = OpCode::from_byte(instruction) {
                let (line, consumed) = Self::disassemble_instruction(bytecode, ip, opcode);
                output.push_str(&format!("{:04} | {}\n", ip, line));
                ip += consumed;
            } else {
                output.push_str(&format!("{:04} | UNKNOWN({})\n", ip, instruction));
                ip += 1;
            }
        }

        output.push_str("\n=== Constants ===\n");
        for (idx, constant) in bytecode.constants.iter().enumerate() {
            output.push_str(&format!("{:3} | {}\n", idx, constant));
        }

        output
    }

    /// 단일 명령어를 문자열과 소비한 바이트 수로 변환
    fn disassemble_instruction(bytecode: &Bytecode, ip: usize, opcode: OpCode) -> (String, usize) {
        let width = opcode.operand_width();

        if width == 0 {
            (format!("{}", opcode.name()), 1)
        } else if width == 1 {
            let operand = bytecode.instructions.get(ip + 1).copied().unwrap_or(0) as u16;
            match opcode {
                OpCode::OpGetLocal | OpCode::OpSetLocal | OpCode::OpCall => {
                    (format!("{} {}", opcode.name(), operand), 2)
                }
                _ => (format!("{} {}", opcode.name(), operand), 2),
            }
        } else if width == 2 {
            let high = bytecode.instructions.get(ip + 1).copied().unwrap_or(0) as u16;
            let low = bytecode.instructions.get(ip + 2).copied().unwrap_or(0) as u16;
            let operand = (high << 8) | low;

            match opcode {
                OpCode::OpConstant => {
                    let constant = bytecode.get_constant(operand as usize).unwrap_or(0);
                    (
                        format!("{} {} ({})", opcode.name(), operand, constant),
                        3,
                    )
                }
                OpCode::OpJump | OpCode::OpJumpNotTruthy => {
                    (format!("{} {:04}", opcode.name(), operand), 3)
                }
                OpCode::OpArray | OpCode::OpHash => {
                    (format!("{} {}", opcode.name(), operand), 3)
                }
                _ => (format!("{} {}", opcode.name(), operand), 3),
            }
        } else {
            (format!("{} (?)", opcode.name()), 1)
        }
    }

    /// 정의된 OpCode 목록 출력
    pub fn print_instructions() {
        println!("=== Available Instructions ===");
        let opcodes = vec![
            OpCode::OpConstant,
            OpCode::OpAdd,
            OpCode::OpSub,
            OpCode::OpMul,
            OpCode::OpDiv,
            OpCode::OpTrue,
            OpCode::OpFalse,
            OpCode::OpEqual,
            OpCode::OpNotEqual,
            OpCode::OpLessThan,
            OpCode::OpGreaterThanOrEqual,
            OpCode::OpBang,
            OpCode::OpMinus,
            OpCode::OpJump,
            OpCode::OpJumpNotTruthy,
            OpCode::OpNull,
            OpCode::OpPop,
            OpCode::OpReturnValue,
            OpCode::OpReturn,
            OpCode::OpGetLocal,
            OpCode::OpSetLocal,
            OpCode::OpArray,
            OpCode::OpHash,
            OpCode::OpIndex,
            OpCode::OpCall,
            OpCode::OpEnd,
        ];

        for op in opcodes {
            println!(
                "{:3} | {:<20} (width: {})",
                op.as_byte(),
                op.name(),
                op.operand_width()
            );
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_disassemble_simple() {
        let mut bytecode = Bytecode::new();

        // PUSH 5
        bytecode.add_instruction(OpCode::OpConstant.as_byte());
        let idx = bytecode.add_constant(5);
        bytecode.add_instruction((idx >> 8) as u8);
        bytecode.add_instruction((idx & 0xFF) as u8);

        // PUSH 3
        bytecode.add_instruction(OpCode::OpConstant.as_byte());
        let idx = bytecode.add_constant(3);
        bytecode.add_instruction((idx >> 8) as u8);
        bytecode.add_instruction((idx & 0xFF) as u8);

        // ADD
        bytecode.add_instruction(OpCode::OpAdd.as_byte());

        let output = Disassembler::disassemble(&bytecode);
        assert!(output.contains("CONSTANT"));
        assert!(output.contains("ADD"));
        assert!(output.contains("5"));
        assert!(output.contains("3"));
    }

    #[test]
    fn test_disassemble_jump() {
        let mut bytecode = Bytecode::new();

        // PUSH true
        bytecode.add_instruction(OpCode::OpTrue.as_byte());

        // JUMP_NOT_TRUTHY 0x0005
        bytecode.add_instruction(OpCode::OpJumpNotTruthy.as_byte());
        bytecode.add_instruction(0x00);
        bytecode.add_instruction(0x05);

        let output = Disassembler::disassemble(&bytecode);
        assert!(output.contains("TRUE"));
        assert!(output.contains("JUMP_NOT_TRUTHY"));
        assert!(output.contains("0005"));
    }
}

