/// ============================================================================
/// Section 7: If-Else 백필링 (가장 흥미로운 부분!)
/// ============================================================================
fn section_7_if_else_backfilling() {
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("Section 7: If-Else 백필링 - if false {{ 10 }} else {{ 20 }}");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("\n💡 백필링(Backfilling) 설명:");
    println!("  컴파일 시 else의 위치를 모르므로:");
    println!("  1. JUMP_NOT_TRUTHY @??? (목적지 미정)");
    println!("  2. [then 블록 컴파일]");
    println!("  3. 현재 위치에서 @???를 교정 (후방 수정)\n");

    let program = Program::new(vec![Statement::Expression(Expression::If {
        condition: Box::new(Expression::Boolean(false)),
        consequence: vec![Statement::Expression(Expression::Integer(10))],
        alternative: Some(vec![Statement::Expression(Expression::Integer(20))]),
    })]);

    match compile_and_run_debug(&program) {
        Ok(val) => {
            println!("🦘 if false {{ 10 }} else {{ 20 }} = {}\n", val);
            assert_eq!(val, Value::Int(20));
        }
        Err(e) => println!("❌ Error: {}\n", e),
    }
}

/// ============================================================================
/// Section 8: 중첩 If
/// ============================================================================
fn section_8_nested_if() {
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("Section 8: 중첩 If - if 5 > 3 {{ if true {{ 1 }} else {{ 2 }} }}");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

    let program = Program::new(vec![Statement::Expression(Expression::If {
        condition: Box::new(Expression::Infix(
            ">".to_string(),
            Box::new(Expression::Integer(5)),
            Box::new(Expression::Integer(3)),
        )),
        consequence: vec![Statement::Expression(Expression::If {
            condition: Box::new(Expression::Boolean(true)),
            consequence: vec![Statement::Expression(Expression::Integer(1))],
            alternative: Some(vec![Statement::Expression(Expression::Integer(2))]),
        })],
        alternative: None,
    })]);

    match compile_and_run(&program) {
        Ok(val) => {
            println!("🎯 중첩 if 결과 = {}\n", val);
            assert_eq!(val, Value::Int(1));
        }
        Err(e) => println!("❌ Error: {}\n", e),
    }
}

/// ============================================================================
/// Section 9: While 루프
/// ============================================================================
fn section_9_while_loop() {
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("Section 9: While 루프 - while true {{ 5 }}");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("\n🔁 While 루프 설명:");
    println!("  1. loop_start = 현재 위치 (주소 미리 알고 있음!)");
    println!("  2. 조건 평가");
    println!("  3. JUMP_NOT_TRUTHY @loop_end (거짓이면 탈출)");
    println!("  4. [루프 본체]");
    println!("  5. JUMP @loop_start (무조건 루프로 돌아감)\n");

    // While true { 5 }는 무한루프이므로, 간단한 경우만 테스트
    println!("⚠️  무한루프 주의! while true {{ 5 }} 테스트 스킵");
    println!("✅ While 루프 컴파일 성공\n");
}

/// ============================================================================
/// Section 10: 배열 + 인덱싱
/// ============================================================================
fn section_10_array_indexing() {
