    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("\n💡 백필링(Backfilling) 설명:");
    println!("  컴파일 시 else의 위치를 모르므로:");
    println!("  1. JUMP_NOT_TRUTHY @??? (목적지 미정)");
    println!("  2. [then 블록 컴파일]");
    println!("  3. 현재 위치에서 @???를 교정 (후방 수정)\n");

    let program = Program::new(vec![Statement::Expression(Expression::If {
        condition: Box::new(Expression::Boolean(false)),
        consequence: vec![Statement::Expression(Expression::Integer(10))],
        alternative: Some(vec![Statement::Expression(Expression::Integer(20))]),
    })]);

    match compile_and_run_debug(&program) {
        Ok(val) => {
            println!("🦘 if false {{ 10 }} else {{ 20 }} = {}\n", val);
            assert_eq!(val, Value::Int(20));
        }
        Err(e) => println!("❌ Error: {}\n", e),
    }
}

