/// ============================================================================
/// Section 1: VM 기본 구조
/// ============================================================================
fn section_1_vm_basics() {
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("Section 1: VM 기본 구조 - IP(Instruction Pointer) & Stack");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

    println!("\n📋 가상 머신의 구성 요소:");
    println!("  1. IP (Instruction Pointer): 현재 실행 위치 [0부터 시작]");
    println!("  2. Stack: 값을 저장하는 LIFO 자료구조");
    println!("  3. Bytecode: 컴파일된 명령어 스트림");
    println!("  4. Constants: 리터럴 값 저장소\n");

    println!("📊 실행 흐름:");
    println!("  1. IP = 0 (시작)");
    println!("  2. instructions[IP]에서 OpCode 읽기");
    println!("  3. IP += (1 + operand_bytes)");
    println!("  4. OpCode 실행 (스택 조작)");
    println!("  5. 반복 (IP >= bytecode.len()까지)\n");

    println!("✅ 이번 섹션: VM 아키텍처 소개 완료\n");
}

/// ============================================================================
/// Section 2: 정수 연산 실행
