    let program = Program::new(vec![Statement::Expression(Expression::Infix(
        "+".to_string(),
        Box::new(Expression::Integer(5)),
        Box::new(Expression::Integer(3)),
    ))]);

    match compile_and_run(&program) {
        Ok(val) => {
