/// ============================================================================
/// Section 12: 아키텍처 요약
/// ============================================================================
fn section_12_architecture_summary() {
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    println!("Section 12: 아키텍처 요약 - 백필링의 영광");
    println!("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n");

    println!("📚 v15.2 핵심 개념:\n");

    println!("1️⃣  백필링 (Backfilling):");
    println!("   - 컴파일 시 미래의 주소를 모를 때 사용");
    println!("   - 예: if 조건식 → [then] → 현재 주소로 jump 목표 교정");
    println!("   - change_operand(): 점프 주소를 후방에서 수정\n");

    println!("2️⃣  절대 주소 (Absolute Address):");
    println!("   - 바이트코드 스트림에서 정확한 위치");
    println!("   - 모든 점프는 절대 주소 사용");
    println!("   - 0부터 bytecode.len()-1까지\n");

    println!("3️⃣  OpJump vs OpJumpNotTruthy:");
    println!("   - OpJump: 항상 점프 (true 조건 건너뛰기)");
    println!("   - OpJumpNotTruthy: 거짓이면 점프 (false 조건 건너뛰기)\n");

    println!("4️⃣  While 루프의 특징:");
    println!("   - loop_start가 이미 알려져 있으므로 백필링 불필요");
    println!("   - 조건→JUMP_NOT_TRUTHY→본체→JUMP_back");
    println!("   - 후방 점프 (backward jump)만 사용\n");

    println!("5️⃣  2바이트 피연산자 (Big-Endian):");
    println!("   - 점프 주소: 0x0000 ~ 0xFFFF (최대 64KB 바이트코드)");
    println!("   - high_byte << 8 | low_byte");
    println!("   - 순서: OpCode[1byte] + high[1byte] + low[1byte] = 3bytes\n");

    println!("╔════════════════════════════════════════════════════════════════╗");
    println!("║           ✅ v15.2 완성! 바이트코드 VM의 탄생                  ║");
    println!("║                 다음: v16.0 최적화 (JIT 준비)                   ║");
    println!("╚════════════════════════════════════════════════════════════════╝\n");
}

