     1→// ============================================================================
     2→// VM: Virtual Machine - 바이트코드 실행 엔진
     3→// ============================================================================
     4→
     5→use crate::bytecode::Bytecode;
     6→use crate::opcode::OpCode;
     7→use crate::value::Value;
     8→use std::collections::HashMap;
     9→
    10→/// 가상 머신
    11→pub struct VM {
    12→    bytecode: Bytecode,
    13→    stack: Vec<Value>,
    14→    ip: usize, // Instruction Pointer
    15→}
    16→
    17→impl VM {
    18→    /// 새로운 VM 생성
    19→    pub fn new(bytecode: Bytecode) -> Self {
    20→        VM {
    21→            bytecode,
    22→            stack: Vec::with_capacity(256),
    23→            ip: 0,
    24→        }
    25→    }
    26→
    27→    /// 바이트코드 실행
    28→    pub fn run(&mut self) -> Result<Value, String> {
    29→        while self.ip < self.bytecode.instructions.len() {
    30→            let op_byte = self.bytecode.instructions[self.ip];
    31→            self.ip += 1;
    32→
    33→            let op = OpCode::from_byte(op_byte).ok_or(format!("Unknown opcode: {}", op_byte))?;
    34→
    35→            match op {
    36→                OpCode::OpConstant => {
    37→                    let idx = self.read_u16() as usize;
    38→                    let val = self
    39→                        .bytecode
    40→                        .get_constant(idx)
    41→                        .ok_or(format!("Constant index out of bounds: {}", idx))?;
    42→                    self.stack.push(Value::Int(val));
    43→                }
    44→
    45→                OpCode::OpAdd => {
    46→                    let right = self.stack_pop()?;
    47→                    let left = self.stack_pop()?;
    48→                    match (left, right) {
    49→                        (Value::Int(l), Value::Int(r)) => {
    50→                            self.stack.push(Value::Int(l + r));
    51→                        }
    52→                        _ => return Err("Cannot add non-integers".to_string()),
    53→                    }
    54→                }
    55→
    56→                OpCode::OpSub => {
    57→                    let right = self.stack_pop()?;
    58→                    let left = self.stack_pop()?;
    59→                    match (left, right) {
    60→                        (Value::Int(l), Value::Int(r)) => {
    61→                            self.stack.push(Value::Int(l - r));
    62→                        }
    63→                        _ => return Err("Cannot subtract non-integers".to_string()),
    64→                    }
    65→                }
    66→
    67→                OpCode::OpMul => {
    68→                    let right = self.stack_pop()?;
    69→                    let left = self.stack_pop()?;
    70→                    match (left, right) {
    71→                        (Value::Int(l), Value::Int(r)) => {
    72→                            self.stack.push(Value::Int(l * r));
    73→                        }
    74→                        _ => return Err("Cannot multiply non-integers".to_string()),
    75→                    }
    76→                }
    77→
    78→                OpCode::OpDiv => {
    79→                    let right = self.stack_pop()?;
    80→                    let left = self.stack_pop()?;
    81→                    match (left, right) {
    82→                        (Value::Int(l), Value::Int(r)) => {
    83→                            if r == 0 {
    84→                                return Err("Division by zero".to_string());
    85→                            }
    86→                            self.stack.push(Value::Int(l / r));
    87→                        }
    88→                        _ => return Err("Cannot divide non-integers".to_string()),
    89→                    }
    90→                }
    91→
    92→                OpCode::OpTrue => {
    93→                    self.stack.push(Value::Bool(true));
    94→                }
    95→
    96→                OpCode::OpFalse => {
    97→                    self.stack.push(Value::Bool(false));
    98→                }
    99→
   100→                OpCode::OpEqual => {
   101→                    let right = self.stack_pop()?;
   102→                    let left = self.stack_pop()?;
   103→                    self.stack.push(Value::Bool(left == right));
   104→                }
   105→
   106→                OpCode::OpNotEqual => {
   107→                    let right = self.stack_pop()?;
   108→                    let left = self.stack_pop()?;
   109→                    self.stack.push(Value::Bool(left != right));
   110→                }
   111→
   112→                OpCode::OpLessThan => {
   113→                    let right = self.stack_pop()?;
   114→                    let left = self.stack_pop()?;
   115→                    match (left, right) {
   116→                        (Value::Int(l), Value::Int(r)) => {
   117→                            self.stack.push(Value::Bool(l < r));
   118→                        }
   119→                        _ => return Err("Cannot compare non-integers".to_string()),
   120→                    }
   121→                }
   122→
   123→                OpCode::OpGreaterThanOrEqual => {
   124→                    let right = self.stack_pop()?;
   125→                    let left = self.stack_pop()?;
   126→                    match (left, right) {
   127→                        (Value::Int(l), Value::Int(r)) => {
   128→                            self.stack.push(Value::Bool(l >= r));
   129→                        }
   130→                        _ => return Err("Cannot compare non-integers".to_string()),
   131→                    }
   132→                }
   133→
   134→                OpCode::OpBang => {
   135→                    let val = self.stack_pop()?;
   136→                    self.stack.push(Value::Bool(!val.is_truthy()));
   137→                }
   138→
   139→                OpCode::OpMinus => {
   140→                    let val = self.stack_pop()?;
   141→                    match val {
   142→                        Value::Int(n) => self.stack.push(Value::Int(-n)),
   143→                        _ => return Err("Cannot negate non-integer".to_string()),
   144→                    }
   145→                }
   146→
   147→                OpCode::OpJump => {
   148→                    let target = self.read_u16() as usize;
   149→                    self.ip = target;
   150→                }
   151→
   152→                OpCode::OpJumpNotTruthy => {
   153→                    let target = self.read_u16() as usize;
   154→                    let cond = self.stack_pop()?;
   155→                    if !cond.is_truthy() {
   156→                        self.ip = target;
   157→                    }
   158→                }
   159→
   160→                OpCode::OpNull => {
   161→                    self.stack.push(Value::Null);
   162→                }
   163→
   164→                OpCode::OpPop => {
   165→                    let _ = self.stack_pop()?;
   166→                }
   167→
   168→                OpCode::OpArray => {
   169→                    let count = self.read_u16() as usize;
   170→                    let mut arr = Vec::with_capacity(count);
   171→                    for _ in 0..count {
   172→                        arr.push(self.stack_pop()?);
   173→                    }
   174→                    arr.reverse();
   175→                    self.stack.push(Value::Array(arr));
   176→                }
   177→
   178→                OpCode::OpHash => {
   179→                    let count = self.read_u16() as usize;
   180→                    let mut map = HashMap::new();
   181→                    for _ in 0..count {
   182→                        let val = self.stack_pop()?;
   183→                        let key = match self.stack_pop()? {
   184→                            Value::Int(n) => n.to_string(),
   185→                            _ => return Err("Hash keys must be integers".to_string()),
   186→                        };
   187→                        map.insert(key, val);
   188→                    }
   189→                    self.stack.push(Value::HashMap(map));
   190→                }
   191→
   192→                OpCode::OpIndex => {
   193→                    let idx = self.stack_pop()?;
   194→                    let arr = self.stack_pop()?;
   195→
   196→                    match (arr, idx) {
   197→                        (Value::Array(arr), Value::Int(i)) => {
   198→                            let idx = if i < 0 {
   199→                                (arr.len() as i64 + i) as usize
   200→                            } else {
   201→                                i as usize
   202→                            };
   203→
   204→                            if idx < arr.len() {
   205→                                self.stack.push(arr[idx].clone());
   206→                            } else {
   207→                                self.stack.push(Value::Null);
   208→                            }
   209→                        }
   210→                        (Value::HashMap(map), key_val) => {
   211→                            let key = match key_val {
   212→                                Value::Int(n) => n.to_string(),
   213→                                _ => return Err("Hash keys must be integers".to_string()),
   214→                            };
   215→                            match map.get(&key) {
   216→                                Some(val) => self.stack.push(val.clone()),
   217→                                None => self.stack.push(Value::Null),
   218→                            }
   219→                        }
   220→                        _ => return Err("Invalid indexing operation".to_string()),
   221→                    }
   222→                }
   223→
   224→                OpCode::OpReturnValue | OpCode::OpReturn => {
   225→                    if let OpCode::OpReturnValue = op {
   226→                        return self.stack_pop();
   227→                    } else {
   228→                        return Ok(Value::Null);
   229→                    }
   230→                }
   231→
   232→                OpCode::OpEnd => {
   233→                    break;
   234→                }
   235→
   236→                _ => return Err(format!("Unimplemented opcode: {:?}", op)),
   237→            }
   238→        }
   239→
   240→        // 스택에 값이 남아있으면 반환
   241→        if !self.stack.is_empty() {
   242→            self.stack_pop()
   243→        } else {
   244→            Ok(Value::Null)
   245→        }
   246→    }
   247→
   248→    /// 스택에서 2바이트 읽기 (Big-Endian)
   249→    fn read_u16(&mut self) -> u16 {
   250→        let high = self.bytecode.instructions[self.ip] as u16;
   251→        let low = self.bytecode.instructions[self.ip + 1] as u16;
   252→        self.ip += 2;
   253→        (high << 8) | low
   254→    }
   255→
   256→    /// 스택에서 값 팝
   257→    fn stack_pop(&mut self) -> Result<Value, String> {
   258→        self.stack.pop().ok_or_else(|| "Stack underflow".to_string())
   259→    }
   260→
   261→    /// 스택의 최상단 값 조회 (팝하지 않음)
   262→    pub fn stack_peek(&self) -> Option<&Value> {
   263→        self.stack.last()
   264→    }
   265→
   266→    /// 스택 상태 확인
   267→    pub fn stack(&self) -> &[Value] {
   268→        &self.stack
   269→    }
   270→}
