     4→
     5→use std::collections::HashMap;
     6→use std::fmt;
     7→
     8→/// 런타임 값
     9→#[derive(Debug, Clone, PartialEq)]
    10→pub enum Value {
    11→    /// 정수
    12→    Int(i64),
    13→
    14→    /// 불리언
    15→    Bool(bool),
    16→
    17→    /// null
    18→    Null,
    19→
    20→    /// 배열
    21→    Array(Vec<Value>),
    22→
    23→    /// 해시맵
    24→    HashMap(HashMap<String, Value>),
    25→}
    26→
    27→impl Value {
    28→    /// 값이 참인지 판단
    29→    pub fn is_truthy(&self) -> bool {
    30→        match self {
    31→            Value::Bool(b) => *b,
    32→            Value::Int(0) => false,
    33→            Value::Int(_) => true,
    34→            Value::Null => false,
    35→            Value::Array(_) => true,
    36→            Value::HashMap(_) => true,
    37→        }
    38→    }
    39→}
    40→
    41→impl fmt::Display for Value {
    42→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    43→        match self {
    44→            Value::Int(n) => write!(f, "{}", n),
    45→            Value::Bool(b) => write!(f, "{}", b),
    46→            Value::Null => write!(f, "null"),
    47→            Value::Array(arr) => {
    48→                write!(f, "[")?;
    49→                for (i, v) in arr.iter().enumerate() {
    50→                    if i > 0 {
    51→                        write!(f, ", ")?;
    52→                    }
    53→                    write!(f, "{}", v)?;
    54→                }
    55→                write!(f, "]")
    56→            }
    57→            Value::HashMap(map) => {
    58→                write!(f, "{{")?;
    59→                let mut first = true;
    60→                for (k, v) in map.iter() {
    61→                    if !first {
    62→                        write!(f, ", ")?;
    63→                    }
    64→                    write!(f, "{}: {}", k, v)?;
    65→                    first = false;
    66→                }
    67→                write!(f, "}}")
    68→            }
    69→        }
    70→    }
    71→}
    72→
    73→#[cfg(test)]
    74→mod tests {
    75→    use super::*;
    76→
    77→    #[test]
    78→    fn test_is_truthy_bool() {
    79→        assert!(Value::Bool(true).is_truthy());
    80→        assert!(!Value::Bool(false).is_truthy());
    81→    }
    82→
    83→    #[test]
    84→    fn test_is_truthy_int() {
    85→        assert!(!Value::Int(0).is_truthy());
    86→        assert!(Value::Int(1).is_truthy());
    87→        assert!(Value::Int(-1).is_truthy());
    88→    }
    89→
    90→    #[test]
    91→    fn test_is_truthy_null() {
    92→        assert!(!Value::Null.is_truthy());
    93→    }
    94→
    95→    #[test]
    96→    fn test_is_truthy_array() {
    97→        assert!(Value::Array(vec![]).is_truthy());
    98→        assert!(Value::Array(vec![Value::Int(1)]).is_truthy());
    99→    }
   100→
   101→    #[test]
   102→    fn test_display() {
   103→        assert_eq!(Value::Int(42).to_string(), "42");
   104→        assert_eq!(Value::Bool(true).to_string(), "true");
   105→        assert_eq!(Value::Null.to_string(), "null");
   106→        assert_eq!(
   107→            Value::Array(vec![Value::Int(1), Value::Int(2)]).to_string(),
   108→            "[1, 2]"
   109→        );
   110→    }
   111→}
