    10→
    11→impl Disassembler {
    12→    /// 전체 바이트코드를 문자열로 변환
    13→    pub fn disassemble(bytecode: &Bytecode) -> String {
    14→        let mut output = String::new();
    15→        output.push_str("=== Bytecode Disassembly ===\n");
    16→        output.push_str("Instructions:\n");
    17→
    18→        let mut ip = 0;
    19→        while ip < bytecode.instructions.len() {
    20→            let instruction = bytecode.instructions[ip];
    21→            if let Some(opcode) = OpCode::from_byte(instruction) {
    22→                let (line, consumed) = Self::disassemble_instruction(bytecode, ip, opcode);
    23→                output.push_str(&format!("{:04} | {}\n", ip, line));
    24→                ip += consumed;
    25→            } else {
    26→                output.push_str(&format!("{:04} | UNKNOWN({})\n", ip, instruction));
    27→                ip += 1;
    28→            }
    29→        }
    30→
    31→        output.push_str("\n=== Constants ===\n");
    32→        for (idx, constant) in bytecode.constants.iter().enumerate() {
    33→            output.push_str(&format!("{:3} | {}\n", idx, constant));
    34→        }
    35→
    36→        output
    37→    }
    38→
    39→    /// 단일 명령어를 문자열과 소비한 바이트 수로 변환
    40→    fn disassemble_instruction(bytecode: &Bytecode, ip: usize, opcode: OpCode) -> (String, usize) {
    41→        let width = opcode.operand_width();
    42→
    43→        if width == 0 {
    44→            (format!("{}", opcode.name()), 1)
    45→        } else if width == 1 {
    46→            let operand = bytecode.instructions.get(ip + 1).copied().unwrap_or(0) as u16;
    47→            match opcode {
    48→                OpCode::OpGetLocal | OpCode::OpSetLocal | OpCode::OpCall => {
    49→                    (format!("{} {}", opcode.name(), operand), 2)
    50→                }
    51→                _ => (format!("{} {}", opcode.name(), operand), 2),
    52→            }
    53→        } else if width == 2 {
    54→            let high = bytecode.instructions.get(ip + 1).copied().unwrap_or(0) as u16;
    55→            let low = bytecode.instructions.get(ip + 2).copied().unwrap_or(0) as u16;
    56→            let operand = (high << 8) | low;
    57→
    58→            match opcode {
    59→                OpCode::OpConstant => {
    60→                    let constant = bytecode.get_constant(operand as usize).unwrap_or(0);
    61→                    (
    62→                        format!("{} {} ({})", opcode.name(), operand, constant),
    63→                        3,
    64→                    )
    65→                }
    66→                OpCode::OpJump | OpCode::OpJumpNotTruthy => {
    67→                    let direction = if operand <= ip as u16 { "↑ 후방" } else { "↓ 전방" };
    68→                    (format!("{} {:04} {}", opcode.name(), operand, direction), 3)
    69→                }
    70→                OpCode::OpArray | OpCode::OpHash => {
    71→                    (format!("{} {}", opcode.name(), operand), 3)
    72→                }
    73→                _ => (format!("{} {}", opcode.name(), operand), 3),
    74→            }
    75→        } else {
    76→            (format!("{} (?)", opcode.name()), 1)
    77→        }
    78→    }
