## 2. 각 모듈 역할

### 2.1 `gc_object.rs` (신규 - 핵심)

GC의 모든 힙 관련 타입을 정의합니다.

```rust
// ============================================================================
// gc_object.rs: GC가 관리하는 힙 객체들
// ============================================================================

/// GC 힙에서의 위치 (인덱스)
/// ObjectHeap의 objects 벡터 인덱스를 나타냄
pub type GcRef = usize;

/// GC가 관리하는 힙 객체 (GcRef를 통해서만 접근)
pub struct GcObject {
    /// Mark 단계에서 도달 가능하면 true로 설정
    pub is_marked: bool,
    /// 실제 데이터
    pub data: GcData,
}

/// GC 힙에 저장되는 데이터 종류
pub enum GcData {
    /// 배열: 요소들은 Value로 (Int/Bool은 직접, 중첩 배열은 GcRef)
    Array(Vec<Value>),
    /// 해시맵: 값들도 Value로
    HashMap(HashMap<String, Value>),
    /// 문자열 (향후 확장용)
    Str(String),
}

/// Arena 패턴의 힙 - 모든 GC 객체를 소유
pub struct ObjectHeap {
    /// 힙의 모든 객체 (None = 이미 해제된 슬롯)
    objects: Vec<Option<GcObject>>,

    /// 지금까지 할당된 총 객체 수 (해제된 것 포함)
    total_allocated: usize,

    /// GC를 트리거하는 임계값 (살아있는 객체 수)
    gc_threshold: usize,

    /// GC 실행 횟수 (교육용 통계)
    gc_count: usize,
}

impl ObjectHeap {
    pub fn new() -> Self { ... }
    pub fn with_threshold(threshold: usize) -> Self { ... }

    /// 새 객체 할당 - GcRef(인덱스) 반환
    pub fn alloc(&mut self, data: GcData) -> GcRef { ... }

    /// GcRef로 객체 불변 참조
    pub fn get(&self, gc_ref: GcRef) -> Option<&GcObject> { ... }

    /// GcRef로 객체 가변 참조 (mark 단계에서 사용)
    pub fn get_mut(&mut self, gc_ref: GcRef) -> Option<&mut GcObject> { ... }

    /// 현재 살아있는 객체 수
    pub fn live_count(&self) -> usize { ... }

    /// GC 실행 여부 판단
    pub fn should_collect(&self) -> bool {
        self.live_count() >= self.gc_threshold
    }

    /// [Mark 단계] 루트에서 도달 가능한 모든 객체 마킹
    pub fn mark(&mut self, roots: &[Value]) { ... }

    /// [Mark 내부] 단일 GcRef에서 재귀적으로 마킹
    fn mark_value(&mut self, value: &Value) { ... }
    fn mark_ref(&mut self, gc_ref: GcRef) { ... }

    /// [Sweep 단계] 마킹되지 않은 객체를 None으로 교체
    pub fn sweep(&mut self) -> usize { ... }  // 해제된 객체 수 반환

    /// [전체 GC] mark + sweep
    pub fn collect_garbage(&mut self, roots: &[Value]) -> GcStats { ... }

    /// 모든 is_marked를 false로 초기화 (다음 GC 준비)
    fn reset_marks(&mut self) { ... }
}

/// GC 실행 통계 (교육용)
pub struct GcStats {
    pub objects_before: usize,
    pub objects_after: usize,
    pub objects_freed: usize,
    pub gc_count: usize,
}
```

