```rust
pub struct VM {
    bytecode: Bytecode,
    stack: Vec<Value>,
    ip: usize,
    heap: ObjectHeap,         // ← 추가: GC가 관리하는 힙
}

impl VM {
    pub fn new(bytecode: Bytecode) -> Self {
        VM {
            bytecode,
            stack: Vec::with_capacity(256),
            ip: 0,
            heap: ObjectHeap::with_threshold(16),  // 임계값 16
        }
    }

    pub fn run(&mut self) -> Result<Value, String> {
        // ...기존 코드...

        // OpArray 처리 변경:
        OpCode::OpArray => {
            let count = self.read_u16() as usize;
            let mut arr = Vec::with_capacity(count);
            for _ in 0..count { arr.push(self.stack_pop()?); }
            arr.reverse();

            // GC 트리거 체크 (힙에 할당하기 전)
            if self.heap.should_collect() {
                let stats = self.heap.collect_garbage(&self.stack);
                // 교육용: eprintln! 으로 GC 발생 알림
            }

            let gc_ref = self.heap.alloc(GcData::Array(arr));
            self.stack.push(Value::Array(gc_ref));  // GcRef만 스택에 푸시
        }

        // OpHash 처리 변경:
        OpCode::OpHash => {
            // ...map 구성...
            if self.heap.should_collect() {
                self.heap.collect_garbage(&self.stack);
            }
            let gc_ref = self.heap.alloc(GcData::HashMap(map));
            self.stack.push(Value::HashMap(gc_ref));
        }

        // OpIndex 처리 변경:
        OpCode::OpIndex => {
            let idx = self.stack_pop()?;
            let container = self.stack_pop()?;
            match container {
                Value::Array(gc_ref) => {
                    // 힙에서 실제 배열 조회
                    let arr = self.heap.get(gc_ref)
                        .ok_or("Dangling GcRef")?;
                    // 인덱싱 로직...
                }
                Value::HashMap(gc_ref) => { ... }
                _ => return Err("Invalid indexing"),
            }
        }
    }

    /// 힙 접근 (테스트용)
    pub fn heap(&self) -> &ObjectHeap { &self.heap }
}
