    Int(i64), Bool(bool), Null,
    Array(GcRef),    // ← 인덱스만
    HashMap(GcRef),  // ← 인덱스만
}

impl Value {
    pub fn as_gc_ref(&self) -> Option<GcRef> {
        match self {
            Value::Array(r) | Value::HashMap(r) => Some(*r),
            _ => None,
        }
    }
    pub fn is_truthy(&self) -> bool {
        match self {
            Value::Bool(b) => *b,
            Value::Int(0) => false,
            Value::Int(_) => true,
            Value::Null => false,
            Value::Array(_) | Value::HashMap(_) => true, // GcRef는 항상 truthy
        }
    }
    pub fn display_with_heap(&self, heap: &ObjectHeap) -> String { ... }
}
```

