    let mut arr: Vec<Value> = (0..count)
        .map(|_| self.stack_pop())
        .collect::<Result<Vec<_>, _>>()?;
    arr.reverse();

    if self.heap.should_collect() {
        self.heap.collect_garbage(&self.stack);
    }
    let gc_ref = self.heap.alloc(GcData::Array(arr));
    self.stack.push(Value::Array(gc_ref));
}

