```rust
use crate::value::Value;
use std::collections::HashMap;

/// GC 힙에서의 위치 (인덱스)
pub type GcRef = usize;

/// GC 힙에 저장되는 데이터 종류
pub enum GcData {
    Array(Vec<Value>),
    HashMap(HashMap<String, Value>),
    Str(String),
}

/// GC가 관리하는 힙 객체
pub struct GcObject {
    pub is_marked: bool,     // Mark 단계 플래그
    pub data: GcData,
}

/// Arena 패턴 힙 - 모든 GC 객체를 소유
pub struct ObjectHeap {
    objects: Vec<Option<GcObject>>,  // None = 해제된 슬롯
    total_allocated: usize,
    gc_threshold: usize,
    gc_count: usize,
}

/// GC 실행 통계 (교육용)
pub struct GcStats {
    pub objects_before: usize,
    pub objects_after: usize,
    pub objects_freed: usize,
    pub gc_count: usize,
}
```

**ObjectHeap 주요 메서드:**
- `new() / with_threshold(n)`: 생성
- `alloc(data) -> GcRef`: 빈 슬롯 재사용 or 새 슬롯 추가
- `get(GcRef) -> Option<&GcObject>`: 불변 조회
- `get_mut(GcRef) -> Option<&mut GcObject>`: 가변 조회
- `live_count() -> usize`: 살아있는 객체 수
- `should_collect() -> bool`: live_count >= gc_threshold
- `mark(roots: &[Value])`: worklist DFS (재귀 아닌 loop)
- `sweep() -> usize`: 해제 후 해제 수 반환
- `collect_garbage(roots: &[Value]) -> GcStats`: mark + sweep 통합

**Mark의 핵심: worklist DFS (Rust borrow checker 해결)**
```rust
pub fn mark(&mut self, roots: &[Value]) {
    self.reset_marks();
    let mut worklist: Vec<GcRef> = roots.iter()
        .filter_map(|v| v.as_gc_ref())
        .collect();

    while let Some(gc_ref) = worklist.pop() {
        let Some(Some(obj)) = self.objects.get_mut(gc_ref) else { continue };
        if obj.is_marked { continue; }
        obj.is_marked = true;
        // 자식 GcRef 수집 후 worklist에 push
        let children: Vec<GcRef> = match &obj.data {
            GcData::Array(elems) => elems.iter().filter_map(|v| v.as_gc_ref()).collect(),
            GcData::HashMap(map) => map.values().filter_map(|v| v.as_gc_ref()).collect(),
            GcData::Str(_) => vec![],
        };
        worklist.extend(children);
    }
}
```

**Sweep의 핵심: is_marked=false → None 교체**
```rust
pub fn sweep(&mut self) -> usize {
    let mut freed = 0;
    for slot in self.objects.iter_mut() {
        match slot {
            Some(obj) if !obj.is_marked => { *slot = None; freed += 1; }
            Some(obj) => { obj.is_marked = false; } // 다음 GC 준비
            None => {}
        }
    }
    freed
}
```

