pub struct VM {
    bytecode: Bytecode,
    stack: Vec<Value>,
    ip: usize,
    heap: ObjectHeap,  // 추가!
}

// OpArray 수정:
OpCode::OpArray => {
    let count = self.read_u16() as usize;
    let mut arr = Vec::with_capacity(count);
    for _ in 0..count { arr.push(self.stack_pop()?); }
    arr.reverse();
    if self.heap.should_collect() {
        let stats = self.heap.collect_garbage(&self.stack);
        eprintln!("[GC #{}: {} → {} ({} 해제)]",
            stats.gc_count, stats.objects_before,
            stats.objects_after, stats.objects_freed);
    }
    let gc_ref = self.heap.alloc(GcData::Array(arr));
    self.stack.push(Value::Array(gc_ref));
}

// OpHash 수정 (유사):
// OpIndex 수정:
OpCode::OpIndex => {
    let idx = self.stack_pop()?;
    let container = self.stack_pop()?;
    match container {
        Value::Array(gc_ref) => {
            let arr_data = self.heap.get(gc_ref)
                .ok_or_else(|| "Dangling GcRef".to_string())?;
            // 인덱싱 로직
        }
        Value::HashMap(gc_ref) => { ... }
        _ => return Err("Invalid indexing".to_string()),
    }
}
